from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
import os

def gcs_to_firestore_and_pubsub(data, context):
    # Pull variables from environment variables 
    project_id = os.getenv('PROJECT_ID')
    topic_name = os.getenv('TOPIC_NAME')
    collection_name = os.getenv('COLLECTION_NAME')

    file_name = data['name'] # Name of the uploaded file
    
    # Set up client for Firestore and Pub/Sub
    firestore_db = firestore.Client(project=project_id)
    publisher = pubsub_v1.PublisherClient()
    topic_path = publisher.topic_path(project_id, topic_name)
    
    # Process the file here, depending on what kind of processing you need to do 
    # (e.g., reading a CSV and putting into Firestore/Pub/Sub or something else entirely)
    
    # Add new document to collection in Firestore
    firestore_db.collection(collection_name).document().set({"fileName": file_name}) 
  
    # Publish message to Pub/Sub
    publisher.publish(topic_path, data='New file has been uploaded: {}'.format(file_name).encode())